import csv
from collections import defaultdict
rows=defaultdict(list)
with open('disease_relevant_inhibited_all_normalized_ode/repeat_variability_analysis_20260704_2021/average_curves_by_setting.csv') as f:
    r=csv.DictReader(f)
    for row in r:
        rows[row['setting']].append((float(row['time']),float(row['mean_y'])))
import numpy as np
def t50(s):
    a=sorted(rows[s]); t=np.array([x[0] for x in a]); y=np.array([x[1] for x in a])
    y=(y-y.min())/(y.max()-y.min()+1e-9)
    # crossing times
    out=[]
    for lv in [0.1,0.5,0.9]:
        idx=np.argmax(y>=lv)
        out.append(round(t[idx],2))
    return out, round(t.max(),1)
for s in rows:
    if s.startswith('M0:0_P0:0'):
        print(s, t50(s))
print('---seeded high---')
for s in rows:
    if s.startswith('M0:1e-6'):
        print(s, t50(s))
